                code: `// 1) Fragment interface — your custom contract
public interface OrderRepositoryCustom {
    List<Order> searchComplex(OrderSearch criteria);
}

// 2) Implementation — MUST be named <Fragment>Impl by convention
@RequiredArgsConstructor
class OrderRepositoryCustomImpl implements OrderRepositoryCustom {

    @PersistenceContext
    private EntityManager em;   // drop down to raw JPA when needed

    @Override
    public List<Order> searchComplex(OrderSearch c) {
        CriteriaBuilder cb = em.getCriteriaBuilder();
        CriteriaQuery<Order> q = cb.createQuery(Order.class);
        Root<Order> root = q.from(Order.class);
        List<Predicate> ps = new ArrayList<>();
        if (c.status() != null) ps.add(cb.equal(root.get("status"), c.status()));
        if (c.minTotal() != null) ps.add(cb.ge(root.get("total"), c.minTotal()));
        q.where(ps.toArray(Predicate[]::new));
        return em.createQuery(q).getResultList();
    }
}

// 3) Main repository COMPOSES the fragment + standard CRUD/derived methods
public interface OrderRepository
        extends JpaRepository<Order, Long>, OrderRepositoryCustom {
    List<Order> findByStatus(OrderStatus status);  // derived
    // searchComplex(...) routed to the Impl fragment automatically
}`,
