                code: `-- Classic: keep the latest order per customer, drop older duplicates
WITH ranked AS (
  SELECT o.*,
         ROW_NUMBER() OVER (PARTITION BY customer_id ORDER BY ordered_at DESC) AS rn
  FROM orders o
)
SELECT * FROM ranked WHERE rn = 1;`,
