                lang: `sql`,
                title: `LAST_VALUE needs an explicit full frame`,
                code: `-- ❌ Default frame ends at CURRENT ROW, so LAST_VALUE returns the current row!
SELECT name, salary,
  LAST_VALUE(salary) OVER (ORDER BY salary) AS wrong_last
FROM employees;

-- ✅ Extend the frame to the whole partition
SELECT name, salary,
  LAST_VALUE(salary) OVER (
    ORDER BY salary
    ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING
  ) AS correct_last
FROM employees;`,
                note: `A very common LAST_VALUE gotcha — without an explicit frame it equals the current row.`
