                code: `// Why "O(log n)" beats "O(n)" in practice — fan-out is the whole story.
// Plain Java, runnable. Models page reads, not wall-clock.
public class IndexVsScanComplexity {

    // Linear scan: visit every row (a seq scan with no usable index).
    static long linearScanRowsExamined(long rows) { return rows; }

    // B+Tree point lookup: page reads = tree height = ceil(log_fanout(rows)),
    // plus 1 leaf. Top levels are usually cached, so subtract ~2.
    static long btreePageReads(long rows, int fanout) {
        if (rows <= 1) return 1;
        long pages = (long) Math.ceil(Math.log(rows) / Math.log(fanout));
        return Math.max(1, pages); // height in page reads
    }

    public static void main(String[] args) {
        int fanout = 370; // ~8KB page, ~22-byte entries
        long[] sizes = {1_000L, 1_000_000L, 100_000_000L, 10_000_000_000L};
        System.out.printf("%-16s | %-18s | %-14s%n", "rows", "seq scan (rows)", "btree (reads)");
        System.out.println("-".repeat(54));
        for (long n : sizes) {
            System.out.printf("%-16d | %-18d | %-14d%n",
                n, linearScanRowsExamined(n), btreePageReads(n, fanout));
        }
        // Output shows: 10 BILLION rows -> ~4 page reads vs 10e9 row touches.
        // That 9-orders-of-magnitude gap is why "add an index" is the first move.
    }
}`,
