                code: `import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;

/**
 * Self-contained simulation. A tiny "row" {balance, version} is hammered by
 * many threads doing read-modify-write. We show:
 *   (1) the LOST UPDATE bug (naive read then write), and
 *   (2) the optimistic version-check fix (compare-and-set with retry).
 * No DB, no libraries — just main().
 */
public class OptimisticVsLostUpdate {

  /** A fake DB row guarded only at the single-field level, like a real engine. */
  static final class Row {
    volatile int balance;
    volatile int version;
    Row(int b) { balance = b; }
  }

  /** Naive read-modify-write -> classic lost update under concurrency. */
  static void naiveDeposit(Row row, int amount) {
    int snapshot = row.balance;          // READ
    sleepJitter();                       // simulate think-time / context switch
    row.balance = snapshot + amount;     // WRITE from stale snapshot -> clobbers
  }

  /**
   * Optimistic deposit: read {balance,version}, compute, then commit only if
   * the version is unchanged. Synchronized block here stands in for the DB's
   * atomic "UPDATE ... WHERE version = ?" (0 rows => retry).
   */
  static void optimisticDeposit(Row row, int amount, AtomicInteger retries) {
    while (true) {
      int vSnap = row.version;           // READ version
      int bSnap = row.balance;           // READ balance
      sleepJitter();                     // think-time
      int newBalance = bSnap + amount;   // compute outside the critical section
      synchronized (row) {               // == the atomic compare-and-set in the DB
        if (row.version == vSnap) {      // WHERE version = ?  (nobody changed it)
          row.balance = newBalance;
          row.version = vSnap + 1;       // version = version + 1
          return;                        // committed
        }
      }
      retries.incrementAndGet();         // lost the race -> OptimisticLockException -> retry
    }
  }

  static void sleepJitter() {
    try { Thread.sleep(0, ThreadLocalRandom().nextInt(50_000)); } catch (InterruptedException ignored) {}
  }
  static java.util.concurrent.ThreadLocalRandom ThreadLocalRandom() {
    return java.util.concurrent.ThreadLocalRandom.current();
  }

  static int run(boolean optimistic) throws InterruptedException {
    final int THREADS = 20, DEPOSITS_EACH = 100, AMOUNT = 1;
    Row row = new Row(0);
    AtomicInteger retries = new AtomicInteger();
    ExecutorService pool = Executors.newFixedThreadPool(THREADS);
    CountDownLatch done = new CountDownLatch(THREADS);
    for (int t = 0; t < THREADS; t++) {
      pool.submit(() -> {
        for (int i = 0; i < DEPOSITS_EACH; i++) {
          if (optimistic) optimisticDeposit(row, AMOUNT, retries);
          else            naiveDeposit(row, AMOUNT);
        }
        done.countDown();
      });
    }
    done.await();
    pool.shutdown();
    int expected = THREADS * DEPOSITS_EACH * AMOUNT;
    System.out.printf("%-11s expected=%d actual=%d  lost=%d  retries=%d%n",
        optimistic ? "OPTIMISTIC" : "NAIVE",
        expected, row.balance, expected - row.balance, retries.get());
    return row.balance;
  }

  public static void main(String[] args) throws InterruptedException {
    System.out.println("Each run: 20 threads x 100 deposits of 1 => expected 2000\\n");
    run(false);  // NAIVE: actual < 2000 (updates were lost)
    run(true);   // OPTIMISTIC: actual == 2000 (retries fix the lost updates)
    System.out.println("\\nNaive loses updates; optimistic re-reads and retries until its");
    System.out.println("version check wins, so no deposit is ever silently dropped.");
  }
}`,
