                code: `import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.util.*;

/** Minimal consistent-hashing ring: adding a shard remaps only ~1/N of keys. */
public class ConsistentHashRing {
    private final SortedMap<Long, String> ring = new TreeMap<>();
    private final int vnodes;

    public ConsistentHashRing(int vnodes) { this.vnodes = vnodes; }

    public void addShard(String shard) {
        for (int i = 0; i < vnodes; i++) ring.put(hash(shard + "#" + i), shard);
    }
    public void removeShard(String shard) {
        for (int i = 0; i < vnodes; i++) ring.remove(hash(shard + "#" + i));
    }
    /** Route a key to the next shard clockwise on the ring. */
    public String route(String key) {
        if (ring.isEmpty()) throw new IllegalStateException("no shards");
        long h = hash(key);
        SortedMap<Long, String> tail = ring.tailMap(h);
        Long point = tail.isEmpty() ? ring.firstKey() : tail.firstKey();
        return ring.get(point);
    }
    private long hash(String s) {
        try {
            byte[] d = MessageDigest.getInstance("MD5").digest(s.getBytes(StandardCharsets.UTF_8));
            long h = 0;
            for (int i = 0; i < 8; i++) h = (h << 8) | (d[i] & 0xff);
            return h;
        } catch (Exception e) { throw new RuntimeException(e); }
    }

    public static void main(String[] args) {
        ConsistentHashRing ring = new ConsistentHashRing(150); // 150 vnodes per shard
        for (String s : List.of("shard-0","shard-1","shard-2","shard-3")) ring.addShard(s);

        int N = 100_000;
        Map<String,Integer> before = new TreeMap<>();
        String[] keys = new String[N];
        for (int i = 0; i < N; i++) {
            keys[i] = "user:" + i;
            before.merge(ring.route(keys[i]), 1, Integer::sum);
        }
        System.out.println("Distribution across 4 shards: " + before);

        // Add a 5th shard and measure how many keys MOVE (should be ~1/5, not ~everything).
        ring.addShard("shard-4");
        int moved = 0;
        for (int i = 0; i < N; i++) {
            // recompute; compare to the original owner captured implicitly by re-routing
        }
        // Re-route and count changes vs a snapshot:
        Map<String,String> owner = new HashMap<>();
        ConsistentHashRing base = new ConsistentHashRing(150);
        for (String s : List.of("shard-0","shard-1","shard-2","shard-3")) base.addShard(s);
        for (String k : keys) owner.put(k, base.route(k));
        for (String k : keys) if (!owner.get(k).equals(ring.route(k))) moved++;

        System.out.printf("Keys moved after adding 5th shard: %d / %d (%.1f%%)%n",
                moved, N, 100.0 * moved / N);
        System.out.println("=> consistent hashing moves ~1/N; modulo would move ~80%+");
    }
}`,
